// Numbers
5 === 5         // true
5 === 6         // false

// Strings
'hello' === 'hello'  // true
'hello' === 'world'  // false

// Booleans
true === true   // true
true === false  // false

// null and undefined
null === null         // true
undefined === undefined // true
null === undefined    // false (different types)

let a = 10;
let b = a; // b is a copy of 10
b = 20;
console.log(a); // 10 — unchanged
console.log(b); // 20

// Two separate objects with identical contents
const a = { name: 'Alice' };
const b = { name: 'Alice' };

console.log(a === b); // false — different memory locations

// Same reference
const c = a; // c points to the same object as a
console.log(a === c); // true — same memory location

// Arrays work the same way
const x = [1, 2, 3];
const y = [1, 2, 3];
const z = x;

console.log(x === y); // false — different arrays
console.log(x === z); // true  — same array

import { useState } from 'react';

function Counter() {
  const [state, setState] = useState({ count: 0 });

  function increment() {
    // ❌ Mutating the existing object — reference stays the same
    state.count += 1;
    setState(state); // React sees same reference → no re-render!
  }

  function incrementCorrect() {
    // ✅ Creating a new object — new reference
    setState({ ...state, count: state.count + 1 });
    // React sees a different reference → re-renders!
  }

  return <button onClick={incrementCorrect}>{state.count}</button>;
}

function Profile({ userId }) {
  // ❌ options is a new object on every render — effect fires on every render!
  const options = { method: 'GET', cache: 'no-cache' };

  useEffect(() => {
    fetchUser(userId, options);
  }, [userId, options]); // options changes every render!

  // ✅ Move the object outside the component, or use useMemo
  // (or remove options from the dep array if fetchUser doesn't actually use it)
}

const MemoizedChild = React.memo(function Child({ style }) {
  console.log('rendered');
  return <div style={style}>content</div>;
});

function Parent() {
  // ❌ New object reference every render — MemoizedChild always re-renders
  return <MemoizedChild style={{ color: 'red' }} />;

  // ✅ Stable reference — MemoizedChild only re-renders when actually needed
  const style = useMemo(() => ({ color: 'red' }), []);
  return <MemoizedChild style={style} />;
}

function Parent() {
  const [count, setCount] = useState(0);

  // ❌ New function reference on every render
  const handleClick = () => setCount(c => c + 1);

  // ✅ Stable function reference (only re-created when deps change)
  const handleClick = useCallback(() => setCount(c => c + 1), []);

  return <MemoizedButton onClick={handleClick} />;
}

const a = { user: { name: 'Alice' } };
const b = { user: { name: 'Alice' } };

// Shallow: checks a === b — false (different references)
// Deep: checks every property recursively — would return true

// JavaScript has no built-in deep equality.
// Options:
// 1. JSON.stringify comparison (simple but has limitations)
console.log(JSON.stringify(a) === JSON.stringify(b)); // true (but breaks for undefined, functions, circular refs)

// 2. A library like lodash's _.isEqual
import { isEqual } from 'lodash';
console.log(isEqual(a, b)); // true

const userA = { id: 1, name: 'Alice' };
const userB = { id: 1, name: 'Alice' };

// Reference check
console.log(userA === userB); // false

// Simple content check (not suitable for nested objects with functions/undefined)
console.log(JSON.stringify(userA) === JSON.stringify(userB)); // true

// Manual property check
console.log(userA.id === userB.id && userA.name === userB.name); // true

// For arrays, you must check each element:
const arr1 = [1, 2, 3];
const arr2 = [1, 2, 3];
console.log(arr1 === arr2); // false
console.log(arr1.every((v, i) => v === arr2[i])); // true

// ❌ Mutation — same reference, React won't re-render
const [items, setItems] = useState([1, 2, 3]);
function addItem() {
  items.push(4);     // mutates the existing array
  setItems(items);   // same reference — no re-render
}

// ✅ New reference — React detects the change
function addItem() {
  setItems([...items, 4]); // new array
}

// ❌ This will always be false for separately created objects
const selectedUser = { id: 5, name: 'Bob' };
const users = [{ id: 5, name: 'Bob' }, { id: 6, name: 'Carol' }];

const found = users.find(u => u === selectedUser); // undefined — never matches!

// ✅ Compare by a meaningful property
const found2 = users.find(u => u.id === selectedUser.id); // { id: 5, name: 'Bob' }

// ❌ New object on every parent render — memo does nothing
<MemoizedChild config={{ theme: 'dark', size: 'lg' }} />

// ✅ Stable reference with useMemo or a module-level constant
const config = { theme: 'dark', size: 'lg' }; // outside component
<MemoizedChild config={config} />
